document.querySelectorAll(".dev-tab-bar").forEach(t=>{t.querySelectorAll(".dev-tab-btn").forEach(e=>{e.addEventListener("click",()=>{t.querySelectorAll(".dev-tab-btn").forEach(a=>{a.classList.remove("bg-[#1a1a3e]","text-[var(--purple-light)]"),a.classList.add("bg-transparent","text-white/40")}),e.classList.add("bg-[#1a1a3e]","text-[var(--purple-light)]"),e.classList.remove("bg-transparent","text-white/40")})})});
